class BiasDetector:
    def __init__(self, protected_attributes):
        self.protected_attributes = protected_attributes
        self.bias_threshold = 0.1

    def calculate_demographic_parity(self, predictions, sensitive_features):
        """Calculate demographic parity across protected attributes"""
        groups = {}
        for attr in self.protected_attributes:
            positive_rate = {}
            unique_values = set(sensitive_features[attr])

            for val in unique_values:
                mask = sensitive_features[attr] == val
                positive_count = sum(predictions[mask])
                total_count = sum(mask)
                positive_rate[val] = positive_count / total_count if total_count > 0 else 0

            groups[attr] = positive_rate
        return groups

    def detect_bias(self, predictions, sensitive_features):
        """Check if predictions show significant bias"""
        parity_scores = self.calculate_demographic_parity(predictions, sensitive_features)
        bias_report = {}

        for attr, rates in parity_scores.items():
            values = list(rates.values())
            if len(values) > 1:
                max_rate = max(values)
                min_rate = min(values)
                disparity = max_rate - min_rate

                bias_report[attr] = {
                    'disparity': disparity,
                    'is_biased': disparity > self.bias_threshold,
                    'rates': rates
                }
        return bias_report

# Example usage
sensitive_data = {'gender': ['M', 'F', 'M', 'F', 'M', 'F'],
                 'age_group': ['young', 'old', 'young', 'old', 'young', 'old']}
predictions = [1, 0, 1, 0, 1, 0]

detector = BiasDetector(['gender', 'age_group'])
report = detector.detect_bias(predictions, sensitive_data)
print("Bias Report:", report)
